// Meta sends a GET request to verify the webhook endpoint
// Must echo back hub.challenge if hub.verify_token matches
const params = $input.first().json.query || $input.first().json;
const verifyToken = params['hub.verify_token'];
const challenge = params['hub.challenge'];
const mode = params['hub.mode'];

const EXPECTED_TOKEN = 'scalar_verify_2025'; // Must match Meta App Dashboard

if (mode === 'subscribe' && verifyToken === EXPECTED_TOKEN) {
  return [{ json: { challenge, isVerification: true } }];
}
return [{ json: { error: 'Token mismatch', isVerification: false } }];

const body = $input.first().json.body || $input.first().json;

// Meta sends: { object: 'instagram', entry: [{ messaging: [{ sender: {id}, message: {text} }] }] }
const entries = body.entry || [];
if (!entries.length) return [];

const messaging = entries[0]?.messaging || [];
if (!messaging.length) return [];

const event = messaging[0];
const senderId = event.sender?.id;
const pageId = event.recipient?.id; // this is the clinic's IG page ID
const text = event.message?.text || '';
const mid = event.message?.mid || '';

// Filter: skip echo messages (sent by the page itself) and non-text events
if (!senderId || !text || event.message?.is_echo) return [];

return [{ json: {
  igSenderId: senderId,
  pageId,
  text,
  mid,
  receivedAt: new Date().toISOString()
} }];

const now = new Date();
const hkOffset = 8 * 60;
const utcMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const hkMinutes = (utcMinutes + hkOffset) % (24 * 60);
const hkDay = new Date(now.getTime() + hkOffset * 60000).getUTCDay();

const isWeekday = hkDay >= 1 && hkDay <= 6;
const isOpenHours = hkMinutes >= 540 && hkMinutes < 1140;
const isBusinessHours = isWeekday && isOpenHours;

return [{ json: { ...$input.first().json, isBusinessHours } }];

const messageData = $('Extract IG Message').first().json;
const contactRow = $('node-ig-ah1').first().json[0];
const conversationRows = $('node-ig-ah2').first().json;

const contactId = contactRow?.id;
const existingConversation = conversationRows.length > 0 ? conversationRows[0] : null;
const existingHistory = existingConversation?.history || [];

const updatedHistory = [
  ...existingHistory,
  { role: 'user', content: messageData.text, timestamp: new Date().toISOString() }
];

const recentHistory = updatedHistory.slice(-12);
const openAiMessages = recentHistory.map(m => ({ role: m.role, content: m.content }));

return [{ json: {
  contactId,
  igSenderId: messageData.igSenderId,
  pageId: messageData.pageId,
  inboundText: messageData.text,
  conversationId: existingConversation?.id || null,
  isNewConversation: !existingConversation,
  existingHistory,
  updatedHistory,
  openAiMessages
} }];

const aiRaw = $input.first().json.choices[0].message.content;
const ctx = $('node-ig-ah3').first().json;

let bookingIntent = null;
const intentMatch = aiRaw.match(/\[BOOKING_INTENT\]([\s\S]*?)\[\/BOOKING_INTENT\]/);
if (intentMatch) {
  try { bookingIntent = JSON.parse(intentMatch[1]); } catch(e) {}
}

const aiText = aiRaw.replace(/\[BOOKING_INTENT\][\s\S]*?\[\/BOOKING_INTENT\]/g, '').trim();

const finalHistory = [
  ...ctx.updatedHistory,
  { role: 'assistant', content: aiText, timestamp: new Date().toISOString() }
];

return [{ json: {
  ...ctx,
  aiText,
  bookingIntent,
  hasBookingIntent: bookingIntent !== null,
  finalHistory,
  finalMessageCount: finalHistory.length
} }];

// Return two message records to log in sequence via Supabase
const ctx = $('node-ig-ah5').first().json;

return [
  { json: { contact_id: ctx.contactId, channel: 'instagram', direction: 'inbound', content: ctx.inboundText, metadata: { igSenderId: ctx.igSenderId }, ai_handled: true } },
  { json: { contact_id: ctx.contactId, channel: 'instagram', direction: 'outbound', content: ctx.aiText, metadata: { model: 'gpt-4o', hasBookingIntent: ctx.hasBookingIntent }, ai_handled: true } }
];

const ctx = $('node-ig-ah5').first().json;
const leadRow = $('Insert Lead (Supabase)').first().json[0];

const crmPayload = {
  source: 'Scalar AI Receptionist',
  channel: 'instagram',
  lead_id: leadRow?.id,
  contact_id: ctx.contactId,
  ig_sender_id: ctx.igSenderId,
  service_interest: ctx.bookingIntent?.service,
  preferred_time: ctx.bookingIntent?.preferred_time,
  status: 'consultation_requested',
  captured_at: new Date().toISOString()
};

const CLIENT_CRM_ENDPOINT = 'YOUR_CLIENT_CRM_WEBHOOK_URL';
const CLIENT_NAME = 'Demo Clinic';

return [{ json: { crmPayload, CLIENT_CRM_ENDPOINT, CLIENT_NAME, leadRow } }];
